// Define schema for level completion data
const LevelCompletionSchema = new mongoose.Schema({
  score: Number,
  time: Number,
});

// Define schema for rewards
const RewardSchema = new mongoose.Schema({
  type: String,
  amount: Number,
});

// Define model for level completion data
const LevelCompletionModel = mongoose.model('LevelCompletion', LevelCompletionSchema);

// Define model for rewards
const RewardModel = mongoose.model('Reward', RewardSchema);

// Route for completing levels
app.post('/levels/:id/complete', (req, res) => {
  const levelId = req.params.id;
  const score = req.body.score;
  const time = req.body.time;
  
  // Check if the level exists in the database
  LevelCompletionModel.findOne({ _id: levelId }, (err, level) => {
    if (err) {
      res.status(500).send('Error completing level');
    } else if (!level) {
      res.status(404).send('Level not found');
    } else {
      // Update the level completion data in the database
      LevelCompletionModel.updateOne({ _id: levelId }, { $set: { score, time } }, (err, result) => {
        if (err) {
          res.status(500).send('Error updating level');
        } else {
          // Calculate the rewards based on the client-reported metrics
          const rewardType = calculateRewardType(score, time);
          const rewardAmount = calculateRewardAmount(rewardType);
          
          // Create a new reward document in the database
          const reward = new RewardModel({ type: rewardType, amount: rewardAmount });
          reward.save((err) => {
            if (err) {
              res.status(500).send('Error saving reward');
            } else {
              res.json({ message: 'Level completed successfully' });
            }
          });
        }
      });
    }
  });
});

// Route for claiming rewards
app.post('/rewards/:id/claim', (req, res) => {
  const rewardId = req.params.id;
  
  // Check if the reward exists in the database
  RewardModel.findOne({ _id: rewardId }, (err, reward) => {
    if (err) {
      res.status(500).send('Error claiming reward');
    } else if (!reward) {
      res.status(404).send('Reward not found');
    } else {
      // Update the reward document in the database to indicate it has been claimed
      RewardModel.updateOne({ _id: rewardId }, { $set: { claimed: true } }, (err, result) => {
        if (err) {
          res.status(500).send('Error updating reward');
        } else {
          res.json({ message: 'Reward claimed successfully' });
        }
      });
    }
  });
});

